import { Outlet } from "react-router-dom"
import { useDispatch, useSelector } from "react-redux"
import { RootState } from "store"
import {
  setVisibility,
  toggleVisibility,
} from "store/slices/sidebarVisibilitySlice"

import { Box, SxProps, Theme } from "@mui/material"
import { useTheme } from "@mui/material/styles"

import ArrowForwardOutlinedIcon from "@mui/icons-material/ArrowForwardOutlined"
import CustomBreadcrumbs from "components/CustomBreadcrumbs"

import AppBar from "./AppBar"
import SideBar from "./SideBar"
import Content from "./Content"

const MainLayout = () => {
  const theme = useTheme()

  const dispatch = useDispatch()

  const sidebarVisibility = useSelector(
    (state: RootState) => state.sidebarVisibility
  )

  window.addEventListener("resize", () => {
    if (window.innerWidth < theme.breakpoints.values.sm) {
      dispatch(setVisibility("hidden"))
    } else if (window.innerWidth < theme.breakpoints.values.lg) {
      dispatch(setVisibility("half"))
    } else {
      dispatch(setVisibility("full"))
    }
  })

  return (
    <>
      <AppBar />
      <Box sx={flexWrapperSx}>
        <section className={["sidebar", sidebarVisibility.value].join(" ")}>
          <button
            className="width-toggle"
            onClick={() => dispatch(toggleVisibility())}
          >
            <ArrowForwardOutlinedIcon
              color="primary"
              sx={{ fontSize: "1rem" }}
            />
          </button>
          <SideBar />
        </section>
        <Content>
          <CustomBreadcrumbs />
          <Outlet />
        </Content>
      </Box>
    </>
  )
}

export default MainLayout

const flexWrapperSx: SxProps<Theme> = (theme) => ({
  display: "flex",
  height: "calc(100vh - 60px)",
  "& > .sidebar": {
    position: "relative",
    height: "100%",
    backgroundColor: theme.palette.background.default,
    width: 250,
    transition: "width 1s ease",
    "& > .width-toggle": {
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      backgroundColor: theme.palette.background.default,
      border: `1px solid ${theme.palette.primary.main}`,
      borderRadius: "50%",
      height: theme.spacing(4),
      width: theme.spacing(4),
      cursor: "pointer",

      position: "absolute",
      right: theme.spacing(-2),
      bottom: "15%",
      zIndex: 1,
      transform: "rotate(-180deg)",
      transition: "transform 500ms ease",
    },
    "&.half": {
      width: 60,
      "& > .width-toggle": {
        transform: "rotate(0deg)",
      },
    },
    "&.hidden": {
      display: "none",
    },
  },
  "& > .main": {
    flexGrow: 1,
    height: "100%",
    backgroundColor: theme.palette.grey[200],
    overflow: "auto",
  },
})

const appBarWrapperSx: SxProps<Theme> = (theme) => ({
  display: "flex",
  height: 60,
  backgroundColor: theme.palette.background.default,
  border: `1px solid ${theme.palette.primary.main}`,
})
