import { createSlice, PayloadAction } from "@reduxjs/toolkit"

type Visibility = "full" | "half" | "hidden"

export interface SidebarVisibilityState {
  value: Visibility
}

const isBrowserSupportStorage = typeof Storage !== "undefined"

const getInitialState = (): Visibility => {
  if (window.innerWidth < 600) {
    return "hidden"
  } else if (window.innerWidth < 1200) {
    return "half"
  } else {
    return "full"
  }
}

// get initialState from localStorage
// if it's not exist, 'full' will be the default value
const initialState: SidebarVisibilityState = (() => {
  const visibilityState: SidebarVisibilityState = {
    value: getInitialState(),
  }

  if (!isBrowserSupportStorage) return visibilityState

  const initialVisibility = localStorage.getItem("sidebarVisibility")
  if (!initialVisibility) return visibilityState

  visibilityState.value = initialVisibility as Visibility
  return visibilityState
})()

export const sidebarVisibilitySlice = createSlice({
  name: "sidebarVisibility",
  initialState,
  reducers: {
    setVisibility: (state, action: PayloadAction<Visibility>) => {
      state.value = action.payload

      if (isBrowserSupportStorage) {
        localStorage.setItem("sidebarVisibility", action.payload)
      }
    },
    toggleVisibility: (state) => {
      if (state.value !== "hidden") {
        const newVisibility = state.value === "full" ? "half" : "full"
        state.value = newVisibility

        if (isBrowserSupportStorage) {
          localStorage.setItem("sidebarVisibility", newVisibility)
        }
      }
    },
  },
})

export default sidebarVisibilitySlice

// Action creators are generated for each case reducer function
export const { setVisibility, toggleVisibility } =
  sidebarVisibilitySlice.actions

export const sidebarVisibilityReducer = sidebarVisibilitySlice.reducer
