import { useState } from "react"
import { useNavigate } from "react-router-dom"
import { useDispatch, useSelector } from "react-redux"
import { RootState } from "store"
import { toggleVisibility as toggleDrawerVisibility } from "store/slices/navDrawerVisibilitySlice"
// import { toggleColorMode } from "store/slices/themeColorSlice"

import {
  Box,
  Typography,
  Avatar,
  ButtonBase,
  useMediaQuery,
  Divider,
  // SvgIcon,
  ListItemIcon,
  ListItemText,
  Fade,
  MenuItem,
  Menu,
  SxProps,
  Theme,
  IconButton,
  LinearProgress,
} from "@mui/material"

import { useTheme } from "@mui/material/styles"

import SettingsIcon from "@mui/icons-material/Settings"
import AppsRoundedIcon from "@mui/icons-material/AppsRounded"
import NotificationsRoundedIcon from "@mui/icons-material/NotificationsRounded"
import KeyboardArrowDownRoundedIcon from "@mui/icons-material/KeyboardArrowDownRounded"
import LogoutRoundedIcon from "@mui/icons-material/LogoutRounded"
import MenuRoundedIcon from "@mui/icons-material/MenuRounded"
import ManageAccountsRoundedIcon from "@mui/icons-material/ManageAccountsRounded"

import { ReactComponent as CosterLogo } from "../../assets/logo_24x24.svg"

const AppBar = () => {
  const theme = useTheme()
  const isSmScreen = useMediaQuery(theme.breakpoints.down("sm"))

  const progressVisibility = useSelector(
    (state: RootState) => state.progressVisibility
  )

  return (
    <>
      {!progressVisibility.value || <LinearProgress sx={linearProgressSx} />}
      <Box component="section" sx={appBarSx}>
        {/* <SvgIcon component={Logo} inheritViewBox height={36} width={36}/> */}
        {!isSmScreen && (
          <>
            <CosterLogo height={32} width={32} style={{ marginRight: 16 }} />
            <Typography variant="h6" component="h1" fontWeight="700">
              App Title
            </Typography>
          </>
        )}
        {isSmScreen && <ToggleDrawerButton />}

        <Box flexGrow={1} />
        <Box display="flex">
          <Divider
            orientation="vertical"
            variant="middle"
            flexItem
            sx={dividerSx}
          />
          <IconButton aria-label="setting">
            <SettingsIcon />
          </IconButton>
          <IconButton aria-label="menu">
            <AppsRoundedIcon />
          </IconButton>
          <IconButton aria-label="notification">
            <NotificationsRoundedIcon />
          </IconButton>
          <Divider
            orientation="vertical"
            variant="middle"
            flexItem
            sx={dividerSx}
          />
        </Box>

        <ButtonProfile />

        {/* <Button onClick={() => dispatch(toggleColorMode())}>
        Coster
      </Button> */}
      </Box>
    </>
  )
}

const ToggleDrawerButton = () => {
  const dispatch = useDispatch()

  return (
    <IconButton
      aria-label="toggle-drawer"
      onClick={() => dispatch(toggleDrawerVisibility())}
    >
      <MenuRoundedIcon />
    </IconButton>
  )
}

const appBarSx: SxProps<Theme> = (theme) => ({
  display: "flex",
  alignItems: "center",
  height: 60,
  backgroundColor: theme.palette.background.default,
  borderBottom: `1px solid ${theme.palette.divider}`,
  paddingX: {
    xs: theme.spacing(1),
    sm: theme.spacing(1.8),
  },
})

const linearProgressSx: SxProps<Theme> = (theme) => ({
  width: "100%",
  position: "fixed",
  top: "0",
  left: "0",
  height: "2px",
  backgroundColor: "transparent",
})

const dividerSx: SxProps<Theme> = (theme) => ({
  marginX: theme.spacing(2),
})

export default AppBar

const ButtonProfile = () => {
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null)
  const open = Boolean(anchorEl)

  const handleClose = () => {
    setAnchorEl(null)
  }

  const navigate = useNavigate()

  return (
    <>
      <ButtonBase onClick={(e) => setAnchorEl(e.currentTarget)}>
        <Box display="flex" alignItems="center" ml={1} py={1}>
          <Box lineHeight="100%" mr={2}>
            <Typography
              variant="subtitle2"
              component="span"
              fontWeight="700"
              display="block"
              lineHeight="inherit"
            >
              {" "}
              Jatisian
            </Typography>
            <Typography
              variant="caption"
              lineHeight="inherit"
              sx={(theme) => ({
                display: "flex",
                alignItems: "center",
                "&::before": {
                  content: '""',
                  display: "block",
                  height: theme.spacing(1),
                  width: theme.spacing(1),
                  borderRadius: "50%",
                  backgroundColor: theme.palette.success.light,
                  marginRight: theme.spacing(0.5),
                },
              })}
            >
              {" "}
              online
            </Typography>
          </Box>
          <Avatar
            alt="User"
            sx={(theme) => ({
              height: theme.spacing(3.5),
              width: theme.spacing(3.5),
              marginRight: theme.spacing(0.5),
            })}
          >
            {" "}
            J
          </Avatar>
          <KeyboardArrowDownRoundedIcon fontSize="small" />
        </Box>
      </ButtonBase>
      <Menu
        id="menu-profile-appbar"
        anchorEl={anchorEl}
        open={open}
        keepMounted
        onClose={handleClose}
        TransitionComponent={Fade}
        MenuListProps={{
          "aria-labelledby": "basic-button",
        }}
        anchorOrigin={{
          vertical: "bottom",
          horizontal: "right",
        }}
        transformOrigin={{
          vertical: "top",
          horizontal: "right",
        }}
      >
        <MenuItem
          onClick={() => {
            navigate("/profile")
            handleClose()
          }}
          dense
        >
          <ListItemIcon>
            <ManageAccountsRoundedIcon />
          </ListItemIcon>
          <ListItemText>My Profile</ListItemText>
        </MenuItem>
        <MenuItem
          onClick={() => {
            navigate("/auth/login")
            handleClose()
          }}
          dense
        >
          <ListItemIcon>
            <LogoutRoundedIcon />
          </ListItemIcon>
          <ListItemText>Logout</ListItemText>
        </MenuItem>
      </Menu>
    </>
  )
}
