import { createTheme } from "@mui/material/styles"

export const lightTheme = createTheme({
  palette: {
    mode: "light",
    primary: {
      main: "#38A0F8",
      contrastText: "#ffffff",
    },
  },
  typography: {
    fontFamily: "Arial",
  },
})

export const darkTheme = createTheme({
  palette: {
    mode: "dark",
    primary: {
      main: "#38A0F8",
      contrastText: "#ffffff",
    },
  },
  typography: {
    fontFamily: "Arial",
  },
})
