import { useState } from "react"
import { useNavigate, useLocation } from "react-router-dom"
import { useSelector, useDispatch } from "react-redux"
import { RootState } from "store"
import {
  toggleVisibility as toggleDrawerVisibility,
  setVisibility as setDrawerVisibility,
} from "store/slices/navDrawerVisibilitySlice"

import {
  Box,
  SxProps,
  Theme,
  List,
  ListItem,
  ListItemButton,
  ListItemText,
  ListItemIcon,
  Menu,
  MenuItem,
  Tooltip,
  Fade,
  Drawer,
} from "@mui/material"

import KeyboardArrowRightRoundedIcon from "@mui/icons-material/KeyboardArrowRightRounded"

import links, { SidebarLink } from "./sidebar-links"

const SideBar = () => {
  return (
    <>
      <NavMenu />
      <SideDrawer>
        <NavMenu />
      </SideDrawer>
    </>
  )
}
export default SideBar

const NavMenu = () => {
  const location = useLocation()
  const currentPage = location.pathname.split("/").filter((path) => path)[0]

  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null)
  const open = Boolean(anchorEl)
  const [menuItemEl, setMenuItemEl] = useState<null | JSX.Element[]>(null)

  const dispatch = useDispatch()
  const navigate = useNavigate()

  const handleClick = (
    event: React.MouseEvent<HTMLLIElement, MouseEvent>,
    link: SidebarLink
  ) => {
    if (link.type === "simple") {
      navigate(link.path)
      dispatch(setDrawerVisibility(false))
    } else {
      setMenuItemEl(
        link.sub.map((item) => (
          <MenuItem
            onClick={() => {
              navigate(`${link.path}${item.path}`)
              handleClose()
            }}
            key={item.name}
            dense
          >
            <ListItemText>{item.name}</ListItemText>
          </MenuItem>
        ))
      )
      setAnchorEl(event.currentTarget)
    }
  }

  const handleClose = () => {
    setAnchorEl(null)
    dispatch(setDrawerVisibility(false))
  }

  const sidebarVisibility = useSelector(
    (state: RootState) => state.sidebarVisibility
  )

  return (
    <Box component="nav" sx={navWrapperSx}>
      <List className="nav-item">
        {links.map((item) => (
          <Tooltip
            key={item.name}
            title={item.name}
            placement="right"
            arrow
            disableHoverListener={
              sidebarVisibility.value === "full" ? true : false
            }
            enterDelay={0}
            leaveDelay={0}
          >
            <ListItem disablePadding onClick={(e) => handleClick(e, item)}>
              <ListItemButton
                disableRipple
                selected={item.path.includes(currentPage)}
              >
                <ListItemIcon sx={{ color: "white" }}>
                  <item.icon />
                </ListItemIcon>
                <ListItemText
                  primary={item.name}
                  primaryTypographyProps={{ noWrap: true }}
                />
                {item.type === "nested" && (
                  <KeyboardArrowRightRoundedIcon fontSize="small" />
                )}
              </ListItemButton>
            </ListItem>
          </Tooltip>
        ))}
      </List>
      <Menu
        id="menu-sidebar"
        anchorEl={anchorEl}
        open={open}
        keepMounted
        onClose={handleClose}
        TransitionComponent={Fade}
        MenuListProps={{
          "aria-labelledby": "basic-button",
        }}
        anchorOrigin={{
          vertical: "top",
          horizontal: "right",
        }}
        transformOrigin={{
          vertical: "top",
          horizontal: "left",
        }}
      >
        {menuItemEl}
      </Menu>
    </Box>
  )
}

const SideDrawer = ({ children }: { children: JSX.Element }) => {
  const dispatch = useDispatch()

  const isOpen = useSelector((state: RootState) => state.navDrawerVisibility)

  const handleClose = () => {
    dispatch(toggleDrawerVisibility())
  }

  return (
    <Drawer
      anchor="left"
      open={isOpen.value}
      onClose={handleClose}
      ModalProps={{
        keepMounted: true,
      }}
    >
      <Box width={250} height="100%">
        {children}
      </Box>
    </Drawer>
  )
}

const navWrapperSx: SxProps<Theme> = (theme) => ({
  display: "grid",
  gridTemplateColumns: "60px 1fr",
  gridTemplateRows: "1fr",
  height: "100%",
  overflowX: "hidden",
  "&::before": {
    content: '""',
    backgroundColor: theme.palette.primary.main,
    display: "block",
    gridColumn: "1 / 2",
    gridRow: "1",
  },
  "& > .nav-item": {
    gridColumn: "1 / 3",
    gridRow: "1",
    padding: 0,
    "& .MuiListItemButton-root": {
      "&:hover, &.Mui-selected": {
        backgroundColor: theme.palette.primary.main,
        color: theme.palette.primary.contrastText,
        "& .MuiListItemIcon-root svg": {
          transform: "scale(1.15)",
        },
      },
      "& .MuiListItemIcon-root svg": {
        color: theme.palette.primary.contrastText,
        transition: "transform 300ms ease",
      },
    },
  },
})
