import { createSlice } from "@reduxjs/toolkit"

export interface ColorState {
  value: "light" | "dark"
}

const isBrowserSupportStorage = typeof Storage !== "undefined"

// get initialState from localStorage
// if it's not exist, 'light' will be the default value
const initialState: ColorState = (() => {
  const colorState: ColorState = {
    value: "light",
  }
  if (isBrowserSupportStorage) {
    const initialColor = localStorage.getItem("colorMode") ?? "light"
    colorState.value = initialColor as "light" | "dark"
  }
  return colorState
})()

export const themeColorSlice = createSlice({
  name: "colorMode",
  initialState,
  reducers: {
    toggleColorMode: (state: ColorState) => {
      const newColor = state.value === "light" ? "dark" : "light"
      state.value = newColor

      if (isBrowserSupportStorage) {
        localStorage.setItem("colorMode", newColor)
      }
    },
  },
})

export default themeColorSlice

// Action creators are generated for each case reducer function
export const { toggleColorMode } = themeColorSlice.actions

export const themeColorReducer = themeColorSlice.reducer
