import React, { useEffect, useRef, useState } from "react"
import { Box, SxProps, Theme, Fade } from "@mui/material"

interface CarouselProps {
  height?: number | string
  children: JSX.Element[]
  timeBetweenItem?: number
  fadeTime?: number
}

const Carousel = ({
  children,
  height,
  timeBetweenItem,
  fadeTime,
}: CarouselProps) => {
  const [carouselItems, setCarouselItems] = useState(
    children.map((child, index) => ({
      index: index,
      child: child,
      active: index === 0 ? true : false,
    }))
  )

  const activeIndex = useRef(0)
  const suspendInterval = useRef(false)

  useEffect(() => {
    const interval = setInterval(() => {
      if (suspendInterval.current) {
        suspendInterval.current = false
        return
      }
      activeIndex.current = activeIndex.current + 1
      handleActive()
    }, timeBetweenItem ?? 7000)

    return () => {
      clearInterval(interval)
    }
  }, [])

  const handleClick = (index: number) => {
    activeIndex.current = index
    handleActive()
    suspendInterval.current = true
  }

  const handleActive = () => {
    const newItems = carouselItems.map(({ index, child, active }) => {
      return {
        active: index === activeIndex.current ? true : false,
        child: child,
        index: index,
      }
    })
    if (activeIndex.current === carouselItems.length - 1) {
      activeIndex.current = -1
    }
    setCarouselItems(newItems)
  }

  return (
    <Box sx={rootSx}>
      {carouselItems.map(({ index, child, active }) => (
        <React.Fragment key={index}>
          {active && (
            <Fade in={true} timeout={fadeTime}>
              <Box height={height}>{child}</Box>
            </Fade>
          )}
        </React.Fragment>
      ))}
      <Box className="nav-wrapper">
        {carouselItems.map(({ index, active }) => (
          <span
            className={`nav-item ${active && "active"}`}
            onClick={() => handleClick(index)}
            key={index}
          ></span>
        ))}
      </Box>
    </Box>
  )
}

const rootSx: SxProps<Theme> = (theme) => ({
  "& .nav-wrapper": {
    display: "flex",
    justifyContent: "center",
    gap: "0.3rem",
    "& .nav-item": {
      display: "block",
      width: "2rem",
      height: "0.3rem",
      borderRadius: "0.15rem",
      backgroundColor: theme.palette.grey[400],
      "&.active": {
        backgroundColor: theme.palette.primary.main,
      },
      "&:hover": {
        cursor: "pointer",
        backgroundColor: theme.palette.primary.main,
      },
    },
  },
})

interface CarouselItemProp {
  children: JSX.Element[]
}

Carousel.Item = ({ children }: CarouselItemProp) => <>{children}</>

export default Carousel
