import { createSlice, PayloadAction } from "@reduxjs/toolkit"

export interface NavDrawerVisibilityState {
  value: boolean
}

const initialState: NavDrawerVisibilityState = {
  value: false,
}

export const navDrawerVisibilitySlice = createSlice({
  name: "navDrawerVisibility",
  initialState,
  reducers: {
    toggleVisibility: (state) => {
      state.value = !state.value
    },
    setVisibility: (state, action: PayloadAction<boolean>) => {
      if (state.value === action.payload) return
      state.value = action.payload
    },
  },
})

export default navDrawerVisibilitySlice

// Action creators are generated for each case reducer function
export const { toggleVisibility, setVisibility } =
  navDrawerVisibilitySlice.actions

export const navDrawerVisibilityReducer = navDrawerVisibilitySlice.reducer
