import { useNavigate } from "react-router-dom"

import {
  Paper,
  Typography,
  SxProps,
  Theme,
  TextField,
  Box,
  Divider,
  Button,
  Link,
} from "@mui/material"

import { ReactComponent as CosterLogo } from "assets/logo_24x24.svg"
import { ReactComponent as CustomerServiceSvg } from "assets/login_page_1.svg"
import { ReactComponent as FeatureSvg } from "assets/undraw_percentages.svg"
import { ReactComponent as BenefitSvg } from "assets/undraw_personal_file.svg"

import Carousel from "components/Carousel"

interface LoginProps {}

const Login = () => {
  const navigate = useNavigate()

  return (
    <Box sx={paperSx}>
      <Paper elevation={6} className="paper">
        <Box className="left">
          <Box className="logo-title">
            <CosterLogo />
            <Typography
              variant="h4"
              component="h1"
              color="primary"
              fontWeight="bold"
            >
              COSTER
            </Typography>
          </Box>
          <Typography variant="h5" component="p">
            Sign in
          </Typography>
          <Typography mb={3}>to access your coster services</Typography>
          <TextField
            className="email-textfield"
            label="Email"
            variant="outlined"
            fullWidth
            size="small"
          />
          <TextField
            className="pwd-textfield"
            label="Password"
            type="password"
            variant="outlined"
            size="small"
            fullWidth
          />
          <Button
            fullWidth
            variant="contained"
            color="primary"
            size="large"
            onClick={() => navigate("/")}
          >
            LOGIN
          </Button>
          <Divider className="horizontal-divider" orientation="horizontal" />
          <Box display="flex" justifyContent="center">
            <Link underline="none">Forgot Password</Link>
          </Box>
        </Box>
        <Divider className="vertical-divider" orientation="vertical" flexItem />
        <Box className="right">
          <Carousel height={370} timeBetweenItem={8000} fadeTime={600}>
            <Carousel.Item>
              <CustomerServiceSvg width="100%" height="200px" />
              <Typography variant="subtitle2" fontWeight="bold" gutterBottom>
                What is Coster ?
              </Typography>
              <Typography mb={3} variant="body2">
                Coster is an omnichannel in one dashboard to get more engagement
                with their customers through Whatsapp and Email.
              </Typography>
            </Carousel.Item>
            <Carousel.Item>
              <BenefitSvg width="100%" height="200px" />
              <Typography variant="subtitle2" fontWeight="bold" gutterBottom>
                Coster benefit
              </Typography>
              <Typography mb={3} variant="body2">
                Coster is a lorem ipsum dolor sit, amet consectetur adipisicing
                elit. Explicabo, harum atque sed natus illo suscipit.
              </Typography>
            </Carousel.Item>
            <Carousel.Item>
              <FeatureSvg width="100%" height="200px" />
              <Typography variant="subtitle2" fontWeight="bold" gutterBottom>
                Coster features
              </Typography>
              <Typography mb={3} variant="body2">
                Lorem ipsum dolor sit, amet consectetur adipisicing elit.
                Eligendi atque magni veritatis, tempora ad similique
                exercitationem itaque, ut, porro in culpa nesciunt voluptatum
                amet.
              </Typography>
            </Carousel.Item>
          </Carousel>
        </Box>
      </Paper>
      <Typography variant="subtitle2" textAlign="center" color="white">
        Don't have a Coster account? Contact Us
      </Typography>
    </Box>
  )
}

const paperSx: SxProps<Theme> = (theme) => ({
  width: "900px",
  marginX: {
    xs: 0,
    sm: 5,
  },
  "& > .MuiPaper-root": {
    height: "500px",
    width: "100%",
    marginBottom: 2,
    borderRadius: {
      xs: 6,
      sm: 2,
    },
    display: "flex",
    "& .left": {
      padding: 6,
      flex: {
        xs: "0 0 100%",
        md: "0 0 55%",
      },
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      "& .logo-title": {
        display: "flex",
        alignItems: "center",
        marginBottom: theme.spacing(2),
        "& svg": {
          width: "2rem",
          height: "2rem",
          marginRight: "0.5rem",
        },
        "& h1": {
          fontSize: "2rem",
        },
      },
      "& .email-textfield": {
        marginBottom: 2,
      },
      "& .pwd-textfield": {
        marginBottom: 3,
      },
      "& .horizontal-divider": {
        marginY: 2,
      },
    },
    "& .right": {
      padding: 8,
      flex: "1 1",
      display: {
        xs: "none",
        md: "flex",
      },
      flexDirection: "column",
      justifyContent: "center",
      "& svg": {
        marginBottom: theme.spacing(2),
      },
    },
    "& .vertical-divider": {
      display: {
        xs: "none",
        md: "block",
      },
    },
  },
})

export default Login
