import { createSlice, PayloadAction } from "@reduxjs/toolkit"

export interface progressVisibilityState {
  value: boolean
}

const initialState: progressVisibilityState = {
  value: false,
}

export const progressVisibilitySlice = createSlice({
  name: "progressVisibility",
  initialState,
  reducers: {
    setVisibility: (state, action: PayloadAction<boolean>) => {
      if (state.value === action.payload) return
      state.value = action.payload
    },
  },
})

export default progressVisibilitySlice

// Action creators are generated for each case reducer function
export const { setVisibility } = progressVisibilitySlice.actions

export const progressVisibilityReducer = progressVisibilitySlice.reducer
