import { Box, SxProps, Theme, BoxProps } from "@mui/material"

interface ContainerProps {
  children: JSX.Element
  boxProps?: BoxProps
}

const Container = ({ children, boxProps }: ContainerProps) => {
  return (
    <Box sx={containerSx} {...boxProps}>
      {children}
    </Box>
  )
}

export default Container

const containerSx: SxProps<Theme> = (theme) => ({
  maxWidth: 1200,
  marginX: "auto",
  paddingX: {
    xs: theme.spacing(1),
    sm: theme.spacing(2),
  },
})
