import { OverridableComponent } from "@mui/material/OverridableComponent"
import { SvgIconTypeMap } from "@mui/material"

import VolumeUpIcon from "@mui/icons-material/VolumeUp"
import CollectionsIcon from "@mui/icons-material/Collections"
import HistoryIcon from "@mui/icons-material/History"

const links: SidebarLink[] = [
  {
    type: "simple",
    name: "Broadcast",
    path: "/broadcasts/my_broadcast",
    icon: VolumeUpIcon,
  },
  {
    type: "nested",
    name: "Gallery",
    path: "/examples",
    icon: CollectionsIcon,
    sub: [
      {
        name: "System",
        path: "/example_2",
      },
    ],
  },
  {
    type: "nested",
    name: "Etc",
    path: "/etc",
    icon: HistoryIcon,
    sub: [
      {
        name: "Users",
        path: "/users",
      },
      {
        name: "Upload",
        path: "/example3",
      },
      {
        name: "Settings",
        path: "/example3",
      },
    ],
  },
]

type NestedLink = {
  type: "nested"
  name: string
  path: string
  icon: OverridableComponent<SvgIconTypeMap<{}, "svg">> & { muiName: string }
  sub: {
    name: string
    path: string
  }[]
}

type SimpleLink = {
  type: "simple"
  name: string
  path: string
  icon: OverridableComponent<SvgIconTypeMap<{}, "svg">> & { muiName: string }
}

export type SidebarLink = NestedLink | SimpleLink

export default links
