import { useState } from "react"

import {
  TextField,
  Box,
  SxProps,
  Theme,
  InputAdornment,
  IconButton,
} from "@mui/material"

import DateRangeRounded from "@mui/icons-material/DateRangeRounded"
import ClearRounded from "@mui/icons-material/ClearRounded"

import DatePicker from "react-datepicker"
import "react-datepicker/dist/react-datepicker.min.css"

interface DateRangePickerProps {
  clear?: boolean
}

const DateRangePicker = ({ clear = false }: DateRangePickerProps) => {
  const [startDate, setStartDate] = useState<null | Date>(null)
  const [endDate, setEndDate] = useState<null | Date>(null)

  const clearDate = () => {
    setStartDate(null)
    setEndDate(null)
  }

  return (
    <Box display="inline" sx={rootSx}>
      <DatePicker
        selectsRange={true}
        startDate={startDate}
        endDate={endDate}
        onChange={(dates) => {
          const [start, end] = dates
          setStartDate(start)
          setEndDate(end)
        }}
        isClearable={false}
        customInput={
          <TextField
            id="outlined-basic"
            size="small"
            label="Outlined"
            variant="outlined"
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <DateRangeRounded />
                </InputAdornment>
              ),
              endAdornment: clear ?? (
                <InputAdornment position="end">
                  <IconButton
                    aria-label="clear date"
                    onClick={clearDate}
                    edge="end"
                  >
                    <ClearRounded />
                  </IconButton>
                </InputAdornment>
              ),
            }}
          />
        }
      />
    </Box>
  )
}

const rootSx: SxProps<Theme> = (theme) => ({
  // general
  "& .react-datepicker-popper .react-datepicker": {
    fontFamily: "'Arial', sans-serif!important",
    borderColor: `${theme.palette.grey[400]}`,

    // remove triangle
    "& .react-datepicker__triangle": {
      display: "none",
    },

    // box
    "& .react-datepicker__header": {
      backgroundColor: `${theme.palette.background.paper}`,
      borderBottom: "none",
    },

    // day label
    "& .react-datepicker__day-name": {
      opacity: "0.5",
    },

    "& .react-datepicker__day-name, .react-datepicker__day": {
      width: "2.3rem",
      paddingY: "0.26rem",
    },

    // navigator
    "& button.react-datepicker__navigation": {
      margin: "1rem 0.7rem",
    },

    // month
    "& .react-datepicker__current-month": {
      marginTop: "1rem",
      marginBottom: "1rem",
      fontWeight: "normal",
    },

    // when selecting
    "& .react-datepicker__day--in-selecting-range": {
      opacity: 0.7,
      backgroundColor: `${theme.palette.primary.main}`,
      "&.react-datepicker__day--selecting-range-start": {
        borderRadius: "50%",
      },
    },

    // when selected
    "& .react-datepicker__day--in-range": {
      backgroundColor: `${theme.palette.primary.main}`,
      "&.react-datepicker__day--range-start, &.react-datepicker__day--range-end":
        {
          borderRadius: "50%",
        },
      "&.react-datepicker__day--outside-month": {
        opacity: 0.7,
      },
    },

    // when selecting or selected
    "& .react-datepicker__day--in-selecting-range, & .react-datepicker__day--in-range":
      {
        "&.react-datepicker__day--keyboard-selected": {
          backgroundColor: `${theme.palette.primary.main}`,
          color: `${theme.palette.common.white}`,
        },
        "&.react-datepicker__day--today": {
          color: `${theme.palette.common.white}`,
        },
      },

    // remove keyboard selected style
    "& .react-datepicker__day--keyboard-selected": {
      backgroundColor: `${theme.palette.background.paper}`,
      color: `${theme.palette.text.primary}`,
    },

    // today style
    "& .react-datepicker__day--today": {
      color: `${theme.palette.primary.main}`,
    },
  },
})

export default DateRangePicker
