import { lazy } from "react"
import { Routes as ReactRoutes, Route, Navigate } from "react-router-dom"

import MainLayout from "layouts/MainLayout"
import AuthLayout from "layouts/AuthLayout"
// import Fallback from "Components/Fallback"
import Susp from "components/Suspense"

// const BroadcastList = lazy(() => import("pages/broadcast/BroadcastList"))
// const BroadcastDetail = lazy(() => import("pages/broadcast/BroadcastDetail"))
// const UserList = lazy(() => import("pages/users/UserList"))
// const NotFound = lazy(() => import("pages/errors/NotFound"))
// const Login = lazy(() => import("pages/auth/Login"))

import BroadcastList from "pages/broadcast/BroadcastList"
import BroadcastDetail from "pages/broadcast/BroadcastDetail"
import UserList from "pages/users/UserList"
import NotFound from "pages/errors/NotFound"
import Login from "pages/auth/Login"

const Routes = () => {
  return (
    <ReactRoutes>
      <Route path="broadcasts" element={<MainLayout />}>
        <Route
          path="my_broadcast"
          element={<Susp Component={BroadcastList} />}
        />
        <Route
          path="my_broadcast/:id"
          element={<Susp Component={BroadcastDetail} />}
        />
        <Route index element={<Navigate to="my_broadcast" />} />
      </Route>
      <Route path="etc" element={<MainLayout />}>
        <Route path="users" element={<Susp Component={UserList} />} />
      </Route>
      <Route path="auth" element={<AuthLayout />}>
        <Route path="login" element={<Susp Component={Login} />} />
      </Route>
      <Route index element={<Navigate to="broadcasts" />} />
      <Route path="*" element={<Susp Component={NotFound} />} />
    </ReactRoutes>
  )
}

interface SProps {
  children: JSX.Element
}
export default Routes
