import { useLocation, Link as RouterLink } from "react-router-dom"

import { Breadcrumbs, Link } from "@mui/material"
import NavigateNextIcon from "@mui/icons-material/NavigateNext"

import CustomContainer from "components/CustomContainer"

const CustomBreadcrumbs = () => {
  let location = useLocation()

  // split with "/" and filter empty string
  let names = location.pathname.split("/").filter((x) => x)

  // Create breadcrumb links element
  const links = names.map((name, index) => {
    if (index === 0) {
      return (
        <Link
          key={name}
          color="inherit"
          style={{ textTransform: "capitalize" }}
          underline="none"
        >
          {name}
        </Link>
      )
    }

    const color = name === names[names.length - 1] ? "text.primary" : "inherit"

    let href = `/${names.slice(0, index + 1).join("/")}`

    name = name.includes("detail") ? "Detail" : name
    name = name.replaceAll("_", " ")

    return (
      <Link
        key={name}
        underline="hover"
        color={color}
        to={href}
        style={{ textTransform: "capitalize" }}
        component={RouterLink}
      >
        {name}
      </Link>
    )
  })

  return (
    <CustomContainer boxProps={{ my: 4 }}>
      <Breadcrumbs
        aria-label="breadcrumb"
        separator={<NavigateNextIcon fontSize="small" />}
      >
        {/* <Link 
          color="inherit"
          style={{textTransform: "capitalize"}}
          underline="none"
        >
          Broadcast
        </Link> */}
        {links}
      </Breadcrumbs>
    </CustomContainer>
  )
}

export default CustomBreadcrumbs
