import { configureStore } from "@reduxjs/toolkit"

import { themeColorReducer } from "./slices/themeColorSlice"
import { sidebarVisibilityReducer } from "./slices/sidebarVisibilitySlice"
import { navDrawerVisibilityReducer } from "./slices/navDrawerVisibilitySlice"
import { progressVisibilityReducer } from "./slices/progressVisibilitySlice"

export const store = configureStore({
  reducer: {
    themeColor: themeColorReducer,
    sidebarVisibility: sidebarVisibilityReducer,
    navDrawerVisibility: navDrawerVisibilityReducer,
    progressVisibility: progressVisibilityReducer,
  },
})

export default store

// Infer the `RootState` and `AppDispatch` types from the store itself
export type RootState = ReturnType<typeof store.getState>
// Inferred type: {posts: PostsState, comments: CommentsState, users: UsersState}
export type AppDispatch = typeof store.dispatch
